patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 6fe969358185..4801b00ed6c4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -853,6 +853,7 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
   Type *Ty = Add.getType();
@@ -870,6 +871,19 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   if (match(Op0, m_Sub(m_Constant(Op00C), m_Value(X))))
     return BinaryOperator::CreateSub(ConstantExpr::getAdd(Op00C, Op1C), X);

+  // add (call @llvm.umax(X, C)), -C --> call @llvm.usub.sat(X, C)
+  if (auto *CI = dyn_cast<CallInst>(Op0)) {
+    if (CI->getIntrinsicID() == Intrinsic::umax) {
+      Value *X = CI->getArgOperand(0);
+      auto *ClampC = dyn_cast<Constant>(CI->getArgOperand(1));
+      if (ClampC && ConstantExpr::getNeg(ClampC) == Op1C) {
+        Function *F =
+            Intrinsic::getDeclaration(Add.getModule(), Intrinsic::usub_sat, Ty);
+        return CallInst::Create(F, {X, ClampC});
+      }
+    }
+  }
+
   Value *Y;

   // add (sub X, Y), -1 --> add (not Y), X
@@ -1007,6 +1021,7 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   return nullptr;
 }

+
 // match variations of a^2 + 2*a*b + b^2
 //
 // to reuse the code between the FP and Int versions, the instruction OpCodes
